document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".menu-toggle"),t=document.querySelector(".main-nav");e&&t&&e.addEventListener("click",()=>{t.classList.toggle("open"),e.setAttribute("aria-expanded",t.classList.contains("open")?"true":"false")});const n=Array.from(document.querySelectorAll(".thumb")),c=document.getElementById("mainCarImage");let r=0;const a=e=>{n.length&&c&&(r=(e+n.length)%n.length,c.src=n[r].dataset.src,n.forEach(e=>e.classList.remove("active")),n[r].classList.add("active"))};if(n.length&&c){a(0),n.forEach((e,t)=>e.addEventListener("click",()=>a(t)));const e=document.querySelector(".gallery-arrow.left"),t=document.querySelector(".gallery-arrow.right");e&&e.addEventListener("click",()=>a(r-1)),t&&t.addEventListener("click",()=>a(r+1))}});